def range_summary(nums):
    if not nums:
        return ''

    nums.sort()
    result = []
    start, end = None, None

    for num in nums:
        if not start or num == end + 1:
            start = num
            end = num
        else:
            if start != end:
                result.append(f'{start}-{end}' if start != end else f'{start}')
            start, end = num, num

    if start != end:
        result.append(f'{start}-{end}' if start != end else f'{start}')

    return ','.join(result)
